(function (global) {
  'use strict';
  function setFeedback(node, message, isError) {
    if (!node) return;
    node.textContent = message || '';
    node.classList.toggle('is-error', Boolean(isError));
  }
  function isValidEmail(value) {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(String(value || '').trim());
  }
  function setSubmitState(button, busy) {
    if (!button) return;
    if (busy) {
      button.disabled = true;
      button.style.pointerEvents = 'none';
      button.style.opacity = '0.65';
      return;
    }
    button.disabled = false;
    button.style.pointerEvents = '';
    button.style.opacity = '';
  }
  async function submitQuote(payload, form) {
    var backend = global.AppBackend || {};
    if (!backend.hasSupabaseConfig || !backend.hasSupabaseConfig()) {
      return { localOnly: true };
    }
    if (!backend.inquiryApi || typeof backend.inquiryApi.submitInquiry !== 'function') {
      return { localOnly: true };
    }
    await backend.inquiryApi.submitInquiry({
      sourceChannel: 'home_request_quote',
      contactName: payload.name,
      companyName: payload.company,
      countryRegion: payload.country,
      workEmail: payload.email,
      phoneWhatsApp: payload.phone,
      productSlug: payload.productType.toLowerCase(),
      requiredVolumeMt: payload.quantity,
      inquiryTopic: 'Request Quote',
      message: payload.message,
    });
    if (form) {
      form.reset();
    }
    return { localOnly: false };
  }
  function getFormPayload(form) {
    function valueOf(fieldName) {
      var field = form.elements ? form.elements.namedItem(fieldName) : null;
      return (field && field.value ? field.value : '').trim();
    }
    return {
      name: valueOf('name'),
      company: valueOf('company'),
      country: valueOf('country'),
      email: valueOf('email'),
      phone: valueOf('phone'),
      productType: valueOf('productType'),
      quantity: valueOf('quantity'),
      message: valueOf('message'),
    };
  }
  function validatePayload(payload) {
    if (!payload.name || !payload.company || !payload.country || !payload.email || !payload.phone || !payload.productType || !payload.quantity || !payload.message) {
      return 'Please complete all fields before sending your quote request.';
    }
    if (!isValidEmail(payload.email)) {
      return 'Please enter a valid email address.';
    }
    return '';
  }
  function initHomeQuoteForm() {
    var form = document.getElementById('buyer-quote-form');
    if (!form) return;
    var feedback = document.getElementById('buyer-quote-feedback');
    var submitButton = document.getElementById('buyer-quote-submit');
    form.addEventListener('submit', async function (event) {
      event.preventDefault();
      var payload = getFormPayload(form);
      var validationMessage = validatePayload(payload);
      if (validationMessage) {
        setFeedback(feedback, validationMessage, true);
        return;
      }
      setSubmitState(submitButton, true);
      setFeedback(feedback, 'Submitting your quote request...', false);
      try {
        var result = await submitQuote(payload, form);
        if (result && result.localOnly) {
          setFeedback(feedback, 'Quote request captured locally. Configure Supabase to receive submissions in your dashboard.', false);
        } else {
          setFeedback(feedback, 'Quote request sent successfully. Our export desk will contact you shortly.', false);
        }
      } catch (error) {
        setFeedback(feedback, (error && error.message) ? error.message : 'Unable to send quote request right now. Please try again.', true);
      } finally {
        setSubmitState(submitButton, false);
      }
    });
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initHomeQuoteForm, { once: true });
  } else {
    initHomeQuoteForm();
  }
})(window);
